using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreateWithDisplayName_EnqueuesCorrectNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_UpdateWithDisplayName_EnqueuesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "user1");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteWithDisplayName_EnqueuesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "admin");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE, "admin");
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Course", "1", "Math", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_TwoArgOverload_EnqueuesCorrectly()
    {
        // Act - uses the overload without entityDisplayName
        _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("7", notification.EntityId);
        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_DequeuesInOrder()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.IsNotNull(first);
        Assert.AreEqual("A", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.IsNotNull(second);
        Assert.AreEqual("B", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.IsNotNull(third);
        Assert.AreEqual("C", third.EntityType);

        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - no-op implementation should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreatedAtIsSet()
    {
        // Arrange
        var before = System.DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Test", "1", "Item", EntityOperation.CREATE);
        var notification = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= System.DateTime.Now.AddSeconds(1));
    }
}

