using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateContext();
        SeedData();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedData()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2021-09-01") }
        );
        _context.SaveChanges();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentDateGroups()
    {
        // Act
        var result = _controller.About();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // 2 distinct enrollment dates
    }

    [TestMethod]
    public void About_GroupsStudentsByEnrollmentDate()
    {
        // Act
        var result = _controller.About();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var groups = viewResult.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(groups);

        var sept2020Group = groups.FirstOrDefault(g => g.EnrollmentDate == DateTime.Parse("2020-09-01"));
        Assert.IsNotNull(sept2020Group);
        Assert.AreEqual(2, sept2020Group.StudentCount); // Carson and Meredith

        var sept2021Group = groups.FirstOrDefault(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
        Assert.IsNotNull(sept2021Group);
        Assert.AreEqual(1, sept2021Group.StudentCount); // Arturo
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessageAndReturnsView()
    {
        // Act
        var result = _controller.Unauthorized();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

