using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateContext();
        SeedData();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedData()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2019-09-01") }
        );
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_DefaultSort_ReturnsViewWithPaginatedList()
    {
        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Act
        var result = _controller.Index("name_desc", null, null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Act
        var result = _controller.Index("Date", null, null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2019, 2020, 2021
        Assert.AreEqual("Anand", model[0].LastName);
        Assert.AreEqual("Alexander", model[1].LastName);
        Assert.AreEqual("Alonso", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Act
        var result = _controller.Index("date_desc", null, null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // 2021, 2020, 2019
        Assert.AreEqual("Alonso", model[0].LastName);
        Assert.AreEqual("Alexander", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudents()
    {
        // Act - search for "Al" matches Alexander and Alonso
        var result = _controller.Index(null, null, "Al", null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        // Act - search by first name "Carson"
        var result = _controller.Index(null, null, "Carson", null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchStringResetsPageToOne()
    {
        // Act - providing a new searchString resets page to 1
        var result = _controller.Index(null, null, "Al", 5);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchWithCurrentFilter_PreservesFilter()
    {
        // Act - no new search string, but has currentFilter
        var result = _controller.Index(null, "Al", null, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // "Al" matches Alexander and Alonso
    }

    [TestMethod]
    public void Index_SetsViewBagSortParams()
    {
        // Act
        _controller.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithSortOrder_SetsCorrectSortParams()
    {
        // Act - when sortOrder is "Date", DateSortParm toggles to "date_desc"
        _controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.Details(student.ID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
        Assert.AreEqual(student.LastName, model.LastName);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultDate()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SavesStudentToDatabase()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            EnrollmentDate = DateTime.Parse("2023-01-15")
        };

        // Act
        _controller.Create(student);

        // Assert - student was saved
        Assert.AreEqual(4, _context.Students.Count()); // 3 seeded + 1 new
        var saved = _context.Students.FirstOrDefault(s => s.LastName == "Doe");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Jane", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_MinDate_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = new DateTime(1700, 1, 1)
        };

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(student);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Edit GET Tests ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.Edit(student.ID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Edit POST Tests ---

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var existingStudent = _context.Students.First();
        // Detach so we can "update" with a new entity
        _context.Entry(existingStudent).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = existingStudent.ID,
            FirstMidName = "UpdatedName",
            LastName = existingStudent.LastName,
            EnrollmentDate = existingStudent.EnrollmentDate
        };

        // Act
        var result = _controller.Edit(updatedStudent);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinDate_AddsModelError()
    {
        // Arrange
        var existingStudent = _context.Students.First();
        _context.Entry(existingStudent).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = existingStudent.ID,
            FirstMidName = existingStudent.FirstMidName,
            LastName = existingStudent.LastName,
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(updatedStudent);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.Delete(student.ID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed Tests ---

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var student = _context.Students.First();

        // Act
        var result = _controller.DeleteConfirmed(student.ID);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(2, _context.Students.Count()); // 3 - 1 = 2
    }

    [TestMethod]
    public void DeleteConfirmed_InvalidId_RedirectsWithError()
    {
        // Act - invalid ID causes Find to return null, which throws in the controller
        // The controller catches exceptions and redirects with error message
        var result = _controller.DeleteConfirmed(9999);

        // Assert - controller catches NullReferenceException and redirects
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }
}

