using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateContext();
        SeedData();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedData()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department
            {
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            },
            new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01")
            }
        );
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Act
        var result = _controller.Index();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = _context.Departments.First();

        // Act
        var result = _controller.Details(dept.DepartmentID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
        Assert.AreEqual(dept.Name, model.Name);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Act
        var result = _controller.Create();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = DateTime.Parse("2023-09-01")
        };

        // Act
        var result = _controller.Create(department);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesInDatabase()
    {
        // Arrange
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = DateTime.Parse("2023-09-01")
        };

        // Act
        _controller.Create(department);

        // Assert
        Assert.AreEqual(3, _context.Departments.Count()); // 2 seeded + 1 new
        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Physics");
        Assert.IsNotNull(saved);
        Assert.AreEqual(200000m, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var department = new Department { Name = "Test" };
        _controller.ModelState.AddModelError("Budget", "Required");

        // Act
        var result = _controller.Create(department);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Edit GET Tests ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = _context.Departments.First();

        // Act
        var result = _controller.Edit(dept.DepartmentID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Edit POST Tests ---

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        var dept = _context.Departments.First();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated English",
            Budget = 400000,
            StartDate = dept.StartDate,
            InstructorID = dept.InstructorID
        };

        // Act
        var result = _controller.Edit(updated);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var dept = new Department { DepartmentID = 1, Name = "Test" };
        _controller.ModelState.AddModelError("Budget", "Required");

        // Act
        var result = _controller.Edit(dept);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        var dept = _context.Departments.First();

        // Act
        var result = _controller.Delete(dept.DepartmentID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed Tests ---

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        // Arrange
        var dept = _context.Departments.First();

        // Act
        var result = _controller.DeleteConfirmed(dept.DepartmentID);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(1, _context.Departments.Count()); // 2 - 1 = 1
    }

    [TestMethod]
    public void DeleteConfirmed_DepartmentNoLongerInDatabase()
    {
        // Arrange
        var dept = _context.Departments.First();
        var deptId = dept.DepartmentID;

        // Act
        _controller.DeleteConfirmed(deptId);

        // Assert
        Assert.IsNull(_context.Departments.Find(deptId));
    }
}

