using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextHelper.CreateContext();
        SeedData();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedData()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01")
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1050 }
            },
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Link department to instructor as administrator
        dept.InstructorID = instructor.ID;
        _context.SaveChanges();
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = _context.Instructors.First();

        // Act
        var result = _controller.Details(instructor.ID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
        Assert.AreEqual("Abercrombie", model.LastName);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            HireDate = DateTime.Parse("2020-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_SavesInDatabase()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            HireDate = DateTime.Parse("2020-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        _controller.Create(instructor, null);

        // Assert
        Assert.AreEqual(2, _context.Instructors.Count()); // 1 seeded + 1 new
        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Doe");
        Assert.IsNotNull(saved);
        Assert.AreEqual("Jane", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Bob",
            LastName = "Smith",
            HireDate = DateTime.Parse("2020-01-15")
        };
        var selectedCourses = new[] { "1050", "4022" };

        // Act
        _controller.Create(instructor, selectedCourses);

        // Assert
        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Smith");
        Assert.IsNotNull(saved);
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "User",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(instructor, null);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = _context.Instructors.First();

        // Act
        var result = _controller.Delete(instructor.ID);

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(9999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed Tests ---

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        // Arrange
        var instructor = _context.Instructors.First();

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(0, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Arrange
        var instructor = _context.Instructors.First();
        var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);
        Assert.IsNotNull(dept.InstructorID); // Verify it's set before deletion

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert - department should have null InstructorID
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNotNull(updatedDept);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

